BEGIN;
DO $$
DECLARE
  v_subject_id UUID;
  v_topic_id UUID;
  v_test_id BIGINT;
BEGIN
  SELECT id INTO v_subject_id FROM test_subjects WHERE name ILIKE '%cardio%' ORDER BY id LIMIT 1;
  IF v_subject_id IS NULL THEN
    INSERT INTO test_subjects (name, description) VALUES ('Cardiovascular System', 'Cardiovascular notes') RETURNING id INTO v_subject_id;
  END IF;
  SELECT id INTO v_topic_id FROM test_topics WHERE name = 'Heart Attack vs Heart Failure vs Cardiac Arrest' ORDER BY (SELECT COUNT(*) FROM test_questions q WHERE q.topic_id = test_topics.id) DESC, created_at ASC LIMIT 1;
  IF v_topic_id IS NULL THEN
    INSERT INTO test_topics (subject_id, name, description, status) VALUES (v_subject_id, 'Heart Attack vs Heart Failure vs Cardiac Arrest', 'Comparison of MI, HF, and arrest with priorities', 'published') RETURNING id INTO v_topic_id;
  END IF;
  SELECT id INTO v_test_id FROM tests WHERE is_active = true ORDER BY id LIMIT 1;
  IF v_test_id IS NULL THEN
    INSERT INTO tests (test_name, system_category, description, is_active)
    VALUES ('Cardiovascular System - MI/HF/Arrest (Generated)', 'Cardiovascular System', 'Auto-generated NCLEX question set', true)
    RETURNING id INTO v_test_id;
  END IF;
  DELETE FROM test_questions WHERE topic_id = v_topic_id AND category = 'MI vs HF vs Cardiac Arrest - NCLEX';
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports MI definition in this cardiovascular emergency scenario?', 'Which finding most strongly supports MI definition in this cardiovascular emergency scenario?', '[{"id": "a", "text": "Heart attack (MI) is blocked coronary blood flow causing heart muscle death."}, {"id": "b", "text": "MI occurs with absent pulse by definition in this note."}, {"id": "c", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "d", "text": "Rhythm assessment should always precede compressions in pulseless states."}]'::jsonb, '["a"]'::jsonb, 'Correct because Heart attack (MI) is blocked coronary blood flow causing heart muscle death. Treat suspected MI as time-sensitive myocardial injury requiring rapid reperfusion strategy.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 1, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse triages rapidly; which interpretation best matches HF definition?', 'The nurse triages rapidly; which interpretation best matches HF definition?', '[{"id": "a", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "b", "text": "This pattern is more consistent with MI atypical in women."}, {"id": "c", "text": "HF always presents with no pulse in this note."}, {"id": "d", "text": "Differentiate pump failure from acute coronary occlusion and arrest during triage."}]'::jsonb, '["d"]'::jsonb, 'Correct because Heart failure is a condition where the heart is too weak or stiff to pump effectively. Differentiate pump failure from acute coronary occlusion and arrest during triage.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 2, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate for Cardiac arrest definition?', 'Which clinical judgment is most accurate for Cardiac arrest definition?', '[{"id": "a", "text": "This pattern is more consistent with STEMI vs NSTEMI."}, {"id": "b", "text": "Cardiac arrest is gradual over months in this note."}, {"id": "c", "text": "Cardiac arrest is sudden stop of all effective heart activity, causing no pulse and unresponsiveness."}, {"id": "d", "text": "Rhythm assessment should always precede compressions in pulseless states."}]'::jsonb, '["c"]'::jsonb, 'Correct because Cardiac arrest is sudden stop of all effective heart activity, causing no pulse and unresponsiveness. Start CPR immediately when pulse is absent and patient is unresponsive.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 3, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Onset differences according to the clinical pattern described?', 'Which statement best reflects Onset differences according to the clinical pattern described?', '[{"id": "a", "text": "Use onset timeline to prioritize differential and response speed."}, {"id": "b", "text": "This pattern is more consistent with MI treatment timing."}, {"id": "c", "text": "HF generally begins in seconds in this note."}, {"id": "d", "text": "Rhythm assessment should always precede compressions in pulseless states."}]'::jsonb, '["a"]'::jsonb, 'Correct because MI onset is sudden in minutes, heart failure is gradual over weeks-months, and cardiac arrest is immediate in seconds. Use onset timeline to prioritize differential and response speed.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 4, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which option aligns best with Pulse consciousness pattern?', 'In urgent prioritization, which option aligns best with Pulse consciousness pattern?', '[{"id": "a", "text": "This pattern is more consistent with MONA in MI."}, {"id": "b", "text": "MI and HF generally have a pulse; cardiac arrest has no pulse and unconsciousness."}, {"id": "c", "text": "Pulse is absent in uncomplicated HF in this note."}, {"id": "d", "text": "Because symptoms are mild, urgent action can be deferred safely."}]'::jsonb, '["b"]'::jsonb, 'Correct because MI and HF generally have a pulse; cardiac arrest has no pulse and unconsciousness. Pulse check rapidly separates arrest from non-arrest chest pain syndromes.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 5, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports MI causes in this cardiovascular emergency scenario?', 'Which finding most strongly supports MI causes in this cardiovascular emergency scenario?', '[{"id": "a", "text": "MI in this note is caused only by chronic valve calcification."}, {"id": "b", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "c", "text": "Smoking lowers MI risk in this note."}, {"id": "d", "text": "Risk-profile plus symptoms should prompt urgent MI protocol activation."}]'::jsonb, '["d"]'::jsonb, 'Correct because MI causes listed include atherosclerotic plaque and clot blocking coronary artery; risk factors include HTN, smoking, cholesterol, diabetes, sedentary lifestyle. Risk-profile plus symptoms should prompt urgent MI protocol activation.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 6, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse triages rapidly; which interpretation best matches MI symptoms classic?', 'The nurse triages rapidly; which interpretation best matches MI symptoms classic?', '[{"id": "a", "text": "Classic MI symptoms include crushing chest pain, radiation to left arm/jaw/neck/back, diaphoresis, nausea, SOB, and anxiety."}, {"id": "b", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "c", "text": "MI pain is always painless in this note."}, {"id": "d", "text": "Because symptoms are mild, urgent action can be deferred safely."}]'::jsonb, '["a"]'::jsonb, 'Correct because Classic MI symptoms include crushing chest pain, radiation to left arm/jaw/neck/back, diaphoresis, nausea, SOB, and anxiety. Clustered ischemic symptoms require immediate ACS workflow.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 7, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate for MI atypical in women?', 'Which clinical judgment is most accurate for MI atypical in women?', '[{"id": "a", "text": "Women always present with classic elephant-on-chest pain in this note."}, {"id": "b", "text": "Avoid missed MI by recognizing atypical presentations."}, {"id": "c", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "d", "text": "Because symptoms are mild, urgent action can be deferred safely."}]'::jsonb, '["b"]'::jsonb, 'Correct because Women may present atypically with fatigue and epigastric pain. Avoid missed MI by recognizing atypical presentations.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 8, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects STEMI vs NSTEMI according to the clinical pattern described?', 'Which statement best reflects STEMI vs NSTEMI according to the clinical pattern described?', '[{"id": "a", "text": "NSTEMI requires ST elevation in this note."}, {"id": "b", "text": "STEMI has ST elevation with complete occlusion; NSTEMI has ST depression with partial occlusion; both have elevated troponin."}, {"id": "c", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "d", "text": "STEMI and NSTEMI both have normal troponin in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because STEMI has ST elevation with complete occlusion; NSTEMI has ST depression with partial occlusion; both have elevated troponin. ECG pattern plus troponin should direct urgency and intervention pathway.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 9, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which option aligns best with MI treatment timing?', 'In urgent prioritization, which option aligns best with MI treatment timing?', '[{"id": "a", "text": "Time-to-reperfusion is critical for myocardial salvage."}, {"id": "b", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "c", "text": "Thrombolytics are never used when PCI unavailable in this note."}, {"id": "d", "text": "This pattern is more consistent with Cardiac arrest rhythms."}]'::jsonb, '["a"]'::jsonb, 'Correct because STEMI requires PCI within 90 minutes; if PCI unavailable, thrombolytics are considered within 30 minutes. Time-to-reperfusion is critical for myocardial salvage.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 10, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports MONA in MI in this cardiovascular emergency scenario?', 'Which finding most strongly supports MONA in MI in this cardiovascular emergency scenario?', '[{"id": "a", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "b", "text": "MONA includes Morphine, Oxygen, Nitrates, and Aspirin in acute MI management from this note."}, {"id": "c", "text": "MONA excludes aspirin in this note."}, {"id": "d", "text": "This pattern is more consistent with Cardiac arrest triggers."}]'::jsonb, '["b"]'::jsonb, 'Correct because MONA includes Morphine, Oxygen, Nitrates, and Aspirin in acute MI management from this note. Initiate first-line MI measures while preparing definitive reperfusion.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 11, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse triages rapidly; which interpretation best matches HF causes?', 'The nurse triages rapidly; which interpretation best matches HF causes?', '[{"id": "a", "text": "Valve disease is unrelated to HF in this note."}, {"id": "b", "text": "Address underlying cause while treating congestion and low output."}, {"id": "c", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "d", "text": "Because symptoms are mild, urgent action can be deferred safely."}]'::jsonb, '["b"]'::jsonb, 'Correct because Heart failure causes listed include post-MI scar, long-term hypertension, valve disease, cardiomyopathy, and COPD causing right-sided failure. Address underlying cause while treating congestion and low output.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 12, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate for Left-sided HF signs?', 'Which clinical judgment is most accurate for Left-sided HF signs?', '[{"id": "a", "text": "Ascites is primary left HF sign in this note."}, {"id": "b", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "c", "text": "Left HF signs include pulmonary edema, crackles, dyspnea, orthopnea, and PND."}, {"id": "d", "text": "Left HF has no respiratory symptoms in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Left HF signs include pulmonary edema, crackles, dyspnea, orthopnea, and PND. Recognize pulmonary congestion and position patient to improve breathing.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 13, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Right-sided HF signs according to the clinical pattern described?', 'Which statement best reflects Right-sided HF signs according to the clinical pattern described?', '[{"id": "a", "text": "Pulmonary crackles are the defining right HF sign in this note."}, {"id": "b", "text": "Track systemic venous congestion and fluid accumulation closely."}, {"id": "c", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "d", "text": "Because symptoms are mild, urgent action can be deferred safely."}]'::jsonb, '["b"]'::jsonb, 'Correct because Right HF signs include JVD, peripheral edema, ascites, and weight gain. Track systemic venous congestion and fluid accumulation closely.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 14, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which option aligns best with HF treatment core?', 'In urgent prioritization, which option aligns best with HF treatment core?', '[{"id": "a", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "b", "text": "This pattern is more consistent with Defibrillation use."}, {"id": "c", "text": "HF treatment listed includes diuretics, ACE inhibitors/ARBs, beta-blockers, digoxin, low sodium diet, and fluid restriction."}, {"id": "d", "text": "Because symptoms are mild, urgent action can be deferred safely."}]'::jsonb, '["c"]'::jsonb, 'Correct because HF treatment listed includes diuretics, ACE inhibitors/ARBs, beta-blockers, digoxin, low sodium diet, and fluid restriction. Combine pharmacologic and fluid/sodium strategies for decongestion and workload reduction.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 15, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Cardiac arrest rhythms in this cardiovascular emergency scenario?', 'Which finding most strongly supports Cardiac arrest rhythms in this cardiovascular emergency scenario?', '[{"id": "a", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "b", "text": "PEA should be defibrillated first in this note."}, {"id": "c", "text": "Rhythm classification determines defibrillation decisions during ACLS."}, {"id": "d", "text": "This pattern is more consistent with Epinephrine timing."}]'::jsonb, '["c"]'::jsonb, 'Correct because Shockable arrest rhythms are ventricular fibrillation and pulseless ventricular tachycardia; non-shockable are asystole and PEA. Rhythm classification determines defibrillation decisions during ACLS.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 16, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse triages rapidly; which interpretation best matches Cardiac arrest triggers?', 'The nurse triages rapidly; which interpretation best matches Cardiac arrest triggers?', '[{"id": "a", "text": "Cardiac arrest can be triggered by MI, electrolyte imbalance, drowning, and drug overdose."}, {"id": "b", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "c", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "d", "text": "Drug overdose cannot cause arrest in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because Cardiac arrest can be triggered by MI, electrolyte imbalance, drowning, and drug overdose. Search reversible triggers while running high-quality resuscitation.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 17, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate for Cardiac arrest signs?', 'Which clinical judgment is most accurate for Cardiac arrest signs?', '[{"id": "a", "text": "Strong peripheral pulse is typical of arrest in this note."}, {"id": "b", "text": "This pattern is more consistent with MI vs arrest distinction."}, {"id": "c", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "d", "text": "Immediate recognition should trigger CPR without delay."}]'::jsonb, '["d"]'::jsonb, 'Correct because Key signs are sudden unresponsiveness, no pulse, no breathing, and cyanosis. Immediate recognition should trigger CPR without delay.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 18, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects CAB order according to the clinical pattern described?', 'Which statement best reflects CAB order according to the clinical pattern described?', '[{"id": "a", "text": "Breathing should always start before compressions in this note."}, {"id": "b", "text": "This pattern is more consistent with Key tests by syndrome."}, {"id": "c", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "d", "text": "Resuscitation sequence emphasizes CAB: Compressions first, then Airway, then Breathing."}]'::jsonb, '["d"]'::jsonb, 'Correct because Resuscitation sequence emphasizes CAB: Compressions first, then Airway, then Breathing. Prioritize circulation immediately to preserve perfusion.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 19, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which option aligns best with Compression quality?', 'In urgent prioritization, which option aligns best with Compression quality?', '[{"id": "a", "text": "This pattern is more consistent with MI definition."}, {"id": "b", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "c", "text": "Shallow compressions are preferred in this note."}, {"id": "d", "text": "High-quality compressions are central to survival in arrest."}]'::jsonb, '["d"]'::jsonb, 'Correct because Compressions should be hard and fast, depth about 2 inches, at 100–120 per minute. High-quality compressions are central to survival in arrest.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 20, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Defibrillation use in this cardiovascular emergency scenario?', 'Which finding most strongly supports Defibrillation use in this cardiovascular emergency scenario?', '[{"id": "a", "text": "All rhythms are treated identically with no shocks in this note."}, {"id": "b", "text": "AED/defibrillation is indicated for V-fib or V-tach rhythms."}, {"id": "c", "text": "AED is first-line for asystole in this note."}, {"id": "d", "text": "Because symptoms are mild, urgent action can be deferred safely."}]'::jsonb, '["b"]'::jsonb, 'Correct because AED/defibrillation is indicated for V-fib or V-tach rhythms. Deliver shock promptly for shockable rhythms while minimizing pauses.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 21, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse triages rapidly; which interpretation best matches Epinephrine timing?', 'The nurse triages rapidly; which interpretation best matches Epinephrine timing?', '[{"id": "a", "text": "Epinephrine is contraindicated in all arrest cases in this note."}, {"id": "b", "text": "Epinephrine is given once only then stopped in this note."}, {"id": "c", "text": "This pattern is more consistent with Cardiac arrest definition."}, {"id": "d", "text": "Follow medication interval while maintaining uninterrupted CPR cycles."}]'::jsonb, '["d"]'::jsonb, 'Correct because Epinephrine is given every 3–5 minutes during cardiac arrest management. Follow medication interval while maintaining uninterrupted CPR cycles.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 22, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate for No pulse NCLEX rule?', 'Which clinical judgment is most accurate for No pulse NCLEX rule?', '[{"id": "a", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "b", "text": "No pulse should be observed without intervention in this note."}, {"id": "c", "text": "NCLEX rule in note: if no pulse, start CPR first and do not delay compressions to check rhythm."}, {"id": "d", "text": "Always check rhythm for several minutes before compressions in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because NCLEX rule in note: if no pulse, start CPR first and do not delay compressions to check rhythm. Immediate compressions outrank delayed diagnostic steps in pulseless patients.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 23, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects MI vs arrest distinction according to the clinical pattern described?', 'Which statement best reflects MI vs arrest distinction according to the clinical pattern described?', '[{"id": "a", "text": "MI and arrest share identical first actions in this note."}, {"id": "b", "text": "Arrest patients are typically ambulatory in this note."}, {"id": "c", "text": "This pattern is more consistent with Pulse consciousness pattern."}, {"id": "d", "text": "Distinguish syndrome quickly to choose PCI pathway vs resuscitation pathway."}]'::jsonb, '["d"]'::jsonb, 'Correct because MI patient is usually awake and in pain, while cardiac arrest patient is unresponsive and pulseless. Distinguish syndrome quickly to choose PCI pathway vs resuscitation pathway.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 24, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which option aligns best with Key tests by syndrome?', 'In urgent prioritization, which option aligns best with Key tests by syndrome?', '[{"id": "a", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "b", "text": "This pattern is more consistent with MI causes."}, {"id": "c", "text": "Key tests listed: MI uses 12-lead ECG and troponin; HF uses BNP/echo/chest X-ray; arrest uses rhythm analysis for shockability."}, {"id": "d", "text": "Arrest diagnosis depends on BNP trend first in this note."}]'::jsonb, '["c"]'::jsonb, 'Correct because Key tests listed: MI uses 12-lead ECG and troponin; HF uses BNP/echo/chest X-ray; arrest uses rhythm analysis for shockability. Select diagnostics that match syndrome and urgency.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 25, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports MI definition in this cardiovascular emergency scenario?', 'Which finding most strongly supports MI definition in this cardiovascular emergency scenario?', '[{"id": "a", "text": "MI occurs with absent pulse by definition in this note."}, {"id": "b", "text": "Treat suspected MI as time-sensitive myocardial injury requiring rapid reperfusion strategy."}, {"id": "c", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "d", "text": "This pattern is more consistent with MI symptoms classic."}]'::jsonb, '["b"]'::jsonb, 'Correct because Heart attack (MI) is blocked coronary blood flow causing heart muscle death. Treat suspected MI as time-sensitive myocardial injury requiring rapid reperfusion strategy.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 26, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse triages rapidly; which interpretation best matches HF definition?', 'The nurse triages rapidly; which interpretation best matches HF definition?', '[{"id": "a", "text": "This pattern is more consistent with MI atypical in women."}, {"id": "b", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "c", "text": "HF means sudden cessation of all heart activity in this note."}, {"id": "d", "text": "Heart failure is a condition where the heart is too weak or stiff to pump effectively."}]'::jsonb, '["d"]'::jsonb, 'Correct because Heart failure is a condition where the heart is too weak or stiff to pump effectively. Differentiate pump failure from acute coronary occlusion and arrest during triage.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 27, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate for Cardiac arrest definition?', 'Which clinical judgment is most accurate for Cardiac arrest definition?', '[{"id": "a", "text": "Start CPR immediately when pulse is absent and patient is unresponsive."}, {"id": "b", "text": "Cardiac arrest is gradual over months in this note."}, {"id": "c", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "d", "text": "This pattern is more consistent with STEMI vs NSTEMI."}]'::jsonb, '["a"]'::jsonb, 'Correct because Cardiac arrest is sudden stop of all effective heart activity, causing no pulse and unresponsiveness. Start CPR immediately when pulse is absent and patient is unresponsive.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 28, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Onset differences according to the clinical pattern described?', 'Which statement best reflects Onset differences according to the clinical pattern described?', '[{"id": "a", "text": "HF generally begins in seconds in this note."}, {"id": "b", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "c", "text": "Cardiac arrest develops gradually over weeks in this note."}, {"id": "d", "text": "MI onset is sudden in minutes, heart failure is gradual over weeks-months, and cardiac arrest is immediate in seconds."}]'::jsonb, '["d"]'::jsonb, 'Correct because MI onset is sudden in minutes, heart failure is gradual over weeks-months, and cardiac arrest is immediate in seconds. Use onset timeline to prioritize differential and response speed.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 29, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which option aligns best with Pulse consciousness pattern?', 'In urgent prioritization, which option aligns best with Pulse consciousness pattern?', '[{"id": "a", "text": "MI always has no pulse at presentation in this note."}, {"id": "b", "text": "Pulse is absent in uncomplicated HF in this note."}, {"id": "c", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "d", "text": "Pulse check rapidly separates arrest from non-arrest chest pain syndromes."}]'::jsonb, '["d"]'::jsonb, 'Correct because MI and HF generally have a pulse; cardiac arrest has no pulse and unconsciousness. Pulse check rapidly separates arrest from non-arrest chest pain syndromes.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 30, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports MI causes in this cardiovascular emergency scenario?', 'Which finding most strongly supports MI causes in this cardiovascular emergency scenario?', '[{"id": "a", "text": "MI causes listed include atherosclerotic plaque and clot blocking coronary artery; risk factors include HTN, smoking, cholesterol, diabetes, sedentary lifestyle."}, {"id": "b", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "c", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "d", "text": "Smoking lowers MI risk in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because MI causes listed include atherosclerotic plaque and clot blocking coronary artery; risk factors include HTN, smoking, cholesterol, diabetes, sedentary lifestyle. Risk-profile plus symptoms should prompt urgent MI protocol activation.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 31, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse triages rapidly; which interpretation best matches MI symptoms classic?', 'The nurse triages rapidly; which interpretation best matches MI symptoms classic?', '[{"id": "a", "text": "Clustered ischemic symptoms require immediate ACS workflow."}, {"id": "b", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "c", "text": "MI pain is always painless in this note."}, {"id": "d", "text": "Because symptoms are mild, urgent action can be deferred safely."}]'::jsonb, '["a"]'::jsonb, 'Correct because Classic MI symptoms include crushing chest pain, radiation to left arm/jaw/neck/back, diaphoresis, nausea, SOB, and anxiety. Clustered ischemic symptoms require immediate ACS workflow.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 32, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate for MI atypical in women?', 'Which clinical judgment is most accurate for MI atypical in women?', '[{"id": "a", "text": "Women may present atypically with fatigue and epigastric pain."}, {"id": "b", "text": "Atypical symptoms rule out MI in this note."}, {"id": "c", "text": "Women always present with classic elephant-on-chest pain in this note."}, {"id": "d", "text": "This pattern is more consistent with Right-sided HF signs."}]'::jsonb, '["a"]'::jsonb, 'Correct because Women may present atypically with fatigue and epigastric pain. Avoid missed MI by recognizing atypical presentations.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 33, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects STEMI vs NSTEMI according to the clinical pattern described?', 'Which statement best reflects STEMI vs NSTEMI according to the clinical pattern described?', '[{"id": "a", "text": "ECG pattern plus troponin should direct urgency and intervention pathway."}, {"id": "b", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "c", "text": "This pattern is more consistent with HF treatment core."}, {"id": "d", "text": "STEMI and NSTEMI both have normal troponin in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because STEMI has ST elevation with complete occlusion; NSTEMI has ST depression with partial occlusion; both have elevated troponin. ECG pattern plus troponin should direct urgency and intervention pathway.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 34, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which option aligns best with MI treatment timing?', 'In urgent prioritization, which option aligns best with MI treatment timing?', '[{"id": "a", "text": "STEMI requires PCI within 90 minutes; if PCI unavailable, thrombolytics are considered within 30 minutes."}, {"id": "b", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "c", "text": "Thrombolytics are never used when PCI unavailable in this note."}, {"id": "d", "text": "Rhythm assessment should always precede compressions in pulseless states."}]'::jsonb, '["a"]'::jsonb, 'Correct because STEMI requires PCI within 90 minutes; if PCI unavailable, thrombolytics are considered within 30 minutes. Time-to-reperfusion is critical for myocardial salvage.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 35, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports MONA in MI in this cardiovascular emergency scenario?', 'Which finding most strongly supports MONA in MI in this cardiovascular emergency scenario?', '[{"id": "a", "text": "This pattern is more consistent with Cardiac arrest triggers."}, {"id": "b", "text": "Initiate first-line MI measures while preparing definitive reperfusion."}, {"id": "c", "text": "MONA excludes aspirin in this note."}, {"id": "d", "text": "MONA is a heart-failure-only acronym in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because MONA includes Morphine, Oxygen, Nitrates, and Aspirin in acute MI management from this note. Initiate first-line MI measures while preparing definitive reperfusion.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 36, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse triages rapidly; which interpretation best matches HF causes?', 'The nurse triages rapidly; which interpretation best matches HF causes?', '[{"id": "a", "text": "Heart failure causes listed include post-MI scar, long-term hypertension, valve disease, cardiomyopathy, and COPD causing right-sided failure."}, {"id": "b", "text": "This pattern is more consistent with Cardiac arrest signs."}, {"id": "c", "text": "Valve disease is unrelated to HF in this note."}, {"id": "d", "text": "HF in this note is caused only by acute anaphylaxis."}]'::jsonb, '["a"]'::jsonb, 'Correct because Heart failure causes listed include post-MI scar, long-term hypertension, valve disease, cardiomyopathy, and COPD causing right-sided failure. Address underlying cause while treating congestion and low output.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 37, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate for Left-sided HF signs?', 'Which clinical judgment is most accurate for Left-sided HF signs?', '[{"id": "a", "text": "This pattern is more consistent with CAB order."}, {"id": "b", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "c", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "d", "text": "Recognize pulmonary congestion and position patient to improve breathing."}]'::jsonb, '["d"]'::jsonb, 'Correct because Left HF signs include pulmonary edema, crackles, dyspnea, orthopnea, and PND. Recognize pulmonary congestion and position patient to improve breathing.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 38, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects Right-sided HF signs according to the clinical pattern described?', 'Which statement best reflects Right-sided HF signs according to the clinical pattern described?', '[{"id": "a", "text": "This pattern is more consistent with Compression quality."}, {"id": "b", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "c", "text": "Right HF signs include JVD, peripheral edema, ascites, and weight gain."}, {"id": "d", "text": "Because symptoms are mild, urgent action can be deferred safely."}]'::jsonb, '["c"]'::jsonb, 'Correct because Right HF signs include JVD, peripheral edema, ascites, and weight gain. Track systemic venous congestion and fluid accumulation closely.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 39, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which option aligns best with HF treatment core?', 'In urgent prioritization, which option aligns best with HF treatment core?', '[{"id": "a", "text": "Combine pharmacologic and fluid/sodium strategies for decongestion and workload reduction."}, {"id": "b", "text": "This pattern is more consistent with Defibrillation use."}, {"id": "c", "text": "Unlimited sodium intake is recommended in this note."}, {"id": "d", "text": "Rhythm assessment should always precede compressions in pulseless states."}]'::jsonb, '["a"]'::jsonb, 'Correct because HF treatment listed includes diuretics, ACE inhibitors/ARBs, beta-blockers, digoxin, low sodium diet, and fluid restriction. Combine pharmacologic and fluid/sodium strategies for decongestion and workload reduction.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 40, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Cardiac arrest rhythms in this cardiovascular emergency scenario?', 'Which finding most strongly supports Cardiac arrest rhythms in this cardiovascular emergency scenario?', '[{"id": "a", "text": "PEA should be defibrillated first in this note."}, {"id": "b", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "c", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "d", "text": "Shockable arrest rhythms are ventricular fibrillation and pulseless ventricular tachycardia; non-shockable are asystole and PEA."}]'::jsonb, '["d"]'::jsonb, 'Correct because Shockable arrest rhythms are ventricular fibrillation and pulseless ventricular tachycardia; non-shockable are asystole and PEA. Rhythm classification determines defibrillation decisions during ACLS.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 41, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse triages rapidly; which interpretation best matches Cardiac arrest triggers?', 'The nurse triages rapidly; which interpretation best matches Cardiac arrest triggers?', '[{"id": "a", "text": "Search reversible triggers while running high-quality resuscitation."}, {"id": "b", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "c", "text": "Drug overdose cannot cause arrest in this note."}, {"id": "d", "text": "This pattern is more consistent with No pulse NCLEX rule."}]'::jsonb, '["a"]'::jsonb, 'Correct because Cardiac arrest can be triggered by MI, electrolyte imbalance, drowning, and drug overdose. Search reversible triggers while running high-quality resuscitation.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 42, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate for Cardiac arrest signs?', 'Which clinical judgment is most accurate for Cardiac arrest signs?', '[{"id": "a", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "b", "text": "Key signs are sudden unresponsiveness, no pulse, no breathing, and cyanosis."}, {"id": "c", "text": "This pattern is more consistent with MI vs arrest distinction."}, {"id": "d", "text": "Cardiac arrest patients remain fully alert in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Key signs are sudden unresponsiveness, no pulse, no breathing, and cyanosis. Immediate recognition should trigger CPR without delay.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 43, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects CAB order according to the clinical pattern described?', 'Which statement best reflects CAB order according to the clinical pattern described?', '[{"id": "a", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "b", "text": "Prioritize circulation immediately to preserve perfusion."}, {"id": "c", "text": "CAB means check rhythm before compressions in this note."}, {"id": "d", "text": "Breathing should always start before compressions in this note."}]'::jsonb, '["b"]'::jsonb, 'Correct because Resuscitation sequence emphasizes CAB: Compressions first, then Airway, then Breathing. Prioritize circulation immediately to preserve perfusion.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 44, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which option aligns best with Compression quality?', 'In urgent prioritization, which option aligns best with Compression quality?', '[{"id": "a", "text": "Shallow compressions are preferred in this note."}, {"id": "b", "text": "Compression rate should be 40/min in this note."}, {"id": "c", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "d", "text": "Compressions should be hard and fast, depth about 2 inches, at 100–120 per minute."}]'::jsonb, '["d"]'::jsonb, 'Correct because Compressions should be hard and fast, depth about 2 inches, at 100–120 per minute. High-quality compressions are central to survival in arrest.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 45, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which finding most strongly supports Defibrillation use in this cardiovascular emergency scenario?', 'Which finding most strongly supports Defibrillation use in this cardiovascular emergency scenario?', '[{"id": "a", "text": "Deliver shock promptly for shockable rhythms while minimizing pauses."}, {"id": "b", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "c", "text": "This pattern is more consistent with HF definition."}, {"id": "d", "text": "AED is first-line for asystole in this note."}]'::jsonb, '["a"]'::jsonb, 'Correct because AED/defibrillation is indicated for V-fib or V-tach rhythms. Deliver shock promptly for shockable rhythms while minimizing pauses.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 46, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse triages rapidly; which interpretation best matches Epinephrine timing?', 'The nurse triages rapidly; which interpretation best matches Epinephrine timing?', '[{"id": "a", "text": "Epinephrine is contraindicated in all arrest cases in this note."}, {"id": "b", "text": "Epinephrine is given every 3–5 minutes during cardiac arrest management."}, {"id": "c", "text": "This pattern is more consistent with Cardiac arrest definition."}, {"id": "d", "text": "Because symptoms are mild, urgent action can be deferred safely."}]'::jsonb, '["b"]'::jsonb, 'Correct because Epinephrine is given every 3–5 minutes during cardiac arrest management. Follow medication interval while maintaining uninterrupted CPR cycles.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 47, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clinical judgment is most accurate for No pulse NCLEX rule?', 'Which clinical judgment is most accurate for No pulse NCLEX rule?', '[{"id": "a", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "b", "text": "Always check rhythm for several minutes before compressions in this note."}, {"id": "c", "text": "This pattern is more consistent with Onset differences."}, {"id": "d", "text": "Immediate compressions outrank delayed diagnostic steps in pulseless patients."}]'::jsonb, '["d"]'::jsonb, 'Correct because NCLEX rule in note: if no pulse, start CPR first and do not delay compressions to check rhythm. Immediate compressions outrank delayed diagnostic steps in pulseless patients.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 48, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which statement best reflects MI vs arrest distinction according to the clinical pattern described?', 'Which statement best reflects MI vs arrest distinction according to the clinical pattern described?', '[{"id": "a", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "b", "text": "This pattern is more consistent with Pulse consciousness pattern."}, {"id": "c", "text": "MI and arrest share identical first actions in this note."}, {"id": "d", "text": "MI patient is usually awake and in pain, while cardiac arrest patient is unresponsive and pulseless."}]'::jsonb, '["d"]'::jsonb, 'Correct because MI patient is usually awake and in pain, while cardiac arrest patient is unresponsive and pulseless. Distinguish syndrome quickly to choose PCI pathway vs resuscitation pathway.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 49, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'In urgent prioritization, which option aligns best with Key tests by syndrome?', 'In urgent prioritization, which option aligns best with Key tests by syndrome?', '[{"id": "a", "text": "Rhythm assessment should always precede compressions in pulseless states."}, {"id": "b", "text": "This pattern is more consistent with MI causes."}, {"id": "c", "text": "Because symptoms are mild, urgent action can be deferred safely."}, {"id": "d", "text": "Select diagnostics that match syndrome and urgency."}]'::jsonb, '["d"]'::jsonb, 'Correct because Key tests listed: MI uses 12-lead ECG and troponin; HF uses BNP/echo/chest X-ray; arrest uses rhythm analysis for shockability. Select diagnostics that match syndrome and urgency.', 'MI vs HF vs Cardiac Arrest - NCLEX', false, 50, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for MI definition. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for MI definition. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "MI is primarily chronic fluid overload in this note."}, {"id": "b", "text": "MI occurs with absent pulse by definition in this note."}, {"id": "c", "text": "MI is an acute emergency condition."}, {"id": "d", "text": "MI involves coronary blood-flow blockage."}, {"id": "e", "text": "Myocardial tissue death occurs with sustained ischemia."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Heart attack (MI) is blocked coronary blood flow causing heart muscle death.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 51, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected HF definition, which statements are correct? (Select all that apply)', 'For suspected HF definition, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "HF patients may still have a pulse and consciousness."}, {"id": "b", "text": "HF means sudden cessation of all heart activity in this note."}, {"id": "c", "text": "HF always presents with no pulse in this note."}, {"id": "d", "text": "HF is impaired pumping/filling efficiency."}, {"id": "e", "text": "HF often develops more gradually than MI."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Heart failure is a condition where the heart is too weak or stiff to pump effectively.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 52, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Cardiac arrest definition. Which elements should be included? (Select all that apply)', 'The nurse plans care around Cardiac arrest definition. Which elements should be included? (Select all that apply)', '[{"id": "a", "text": "Cardiac arrest is gradual over months in this note."}, {"id": "b", "text": "Cardiac arrest patients are usually awake and conversational in this note."}, {"id": "c", "text": "Cardiac arrest has absent pulse."}, {"id": "d", "text": "Cardiac arrest patients are unconscious in this note."}, {"id": "e", "text": "Immediate resuscitation is required in arrest."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Cardiac arrest is sudden stop of all effective heart activity, causing no pulse and unresponsiveness.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 53, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Onset differences? (Select all that apply)', 'During reassessment, which observations support Onset differences? (Select all that apply)', '[{"id": "a", "text": "Cardiac arrest occurs in seconds in this note."}, {"id": "b", "text": "MI is sudden in this note."}, {"id": "c", "text": "Cardiac arrest develops gradually over weeks in this note."}, {"id": "d", "text": "HF is typically gradual in this note."}, {"id": "e", "text": "HF generally begins in seconds in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: MI onset is sudden in minutes, heart failure is gradual over weeks-months, and cardiac arrest is immediate in seconds.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 54, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues from this scenario are consistent with Pulse consciousness pattern? (Select all that apply)', 'Which clues from this scenario are consistent with Pulse consciousness pattern? (Select all that apply)', '[{"id": "a", "text": "MI often presents while conscious in this note."}, {"id": "b", "text": "HF patients may have weak but present pulse in this note."}, {"id": "c", "text": "Cardiac arrest has no pulse in this note."}, {"id": "d", "text": "MI always has no pulse at presentation in this note."}, {"id": "e", "text": "Pulse is absent in uncomplicated HF in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: MI and HF generally have a pulse; cardiac arrest has no pulse and unconsciousness.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 55, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for MI causes. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for MI causes. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Atherosclerosis and thrombosis are listed MI causes."}, {"id": "b", "text": "Smoking lowers MI risk in this note."}, {"id": "c", "text": "HTN/smoking/cholesterol/diabetes are listed risks."}, {"id": "d", "text": "MI in this note is caused only by chronic valve calcification."}, {"id": "e", "text": "Sedentary lifestyle is listed as risk."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: MI causes listed include atherosclerotic plaque and clot blocking coronary artery; risk factors include HTN, smoking, cholesterol, diabetes, sedentary lifestyle.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 56, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected MI symptoms classic, which statements are correct? (Select all that apply)', 'For suspected MI symptoms classic, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "MI pain is always painless in this note."}, {"id": "b", "text": "Radiation to arm/jaw/neck/back is listed."}, {"id": "c", "text": "Radiation is absent in MI in this note."}, {"id": "d", "text": "Crushing chest pain is described in MI."}, {"id": "e", "text": "Diaphoresis and nausea are listed features."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Classic MI symptoms include crushing chest pain, radiation to left arm/jaw/neck/back, diaphoresis, nausea, SOB, and anxiety.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 57, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around MI atypical in women. Which elements should be included? (Select all that apply)', 'The nurse plans care around MI atypical in women. Which elements should be included? (Select all that apply)', '[{"id": "a", "text": "Atypical symptoms rule out MI in this note."}, {"id": "b", "text": "Fatigue can be atypical MI symptom in women."}, {"id": "c", "text": "Epigastric pain may be atypical MI symptom in women."}, {"id": "d", "text": "Women always present with classic elephant-on-chest pain in this note."}, {"id": "e", "text": "Atypical symptoms still warrant urgent evaluation."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Women may present atypically with fatigue and epigastric pain.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 58, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support STEMI vs NSTEMI? (Select all that apply)', 'During reassessment, which observations support STEMI vs NSTEMI? (Select all that apply)', '[{"id": "a", "text": "Troponin elevates in both STEMI and NSTEMI in this note."}, {"id": "b", "text": "STEMI is complete occlusion in this note."}, {"id": "c", "text": "NSTEMI requires ST elevation in this note."}, {"id": "d", "text": "STEMI and NSTEMI both have normal troponin in this note."}, {"id": "e", "text": "NSTEMI is partial occlusion in this note."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: STEMI has ST elevation with complete occlusion; NSTEMI has ST depression with partial occlusion; both have elevated troponin.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 59, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues from this scenario are consistent with MI treatment timing? (Select all that apply)', 'Which clues from this scenario are consistent with MI treatment timing? (Select all that apply)', '[{"id": "a", "text": "Thrombolytics are never used when PCI unavailable in this note."}, {"id": "b", "text": "Door-to-balloon target is 90 minutes for STEMI."}, {"id": "c", "text": "Thrombolytics are considered if PCI unavailable within 30 minutes."}, {"id": "d", "text": "NSTEMI uses anticoagulants and cardiac cath strategy in this note."}, {"id": "e", "text": "STEMI reperfusion can wait 24 hours in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: STEMI requires PCI within 90 minutes; if PCI unavailable, thrombolytics are considered within 30 minutes.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 60, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for MONA in MI. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for MONA in MI. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "MONA is a heart-failure-only acronym in this note."}, {"id": "b", "text": "MONA excludes aspirin in this note."}, {"id": "c", "text": "Nitrates are in MONA in this note."}, {"id": "d", "text": "Aspirin is in MONA in this note."}, {"id": "e", "text": "Morphine is in MONA in this note."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: MONA includes Morphine, Oxygen, Nitrates, and Aspirin in acute MI management from this note.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 61, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected HF causes, which statements are correct? (Select all that apply)', 'For suspected HF causes, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "HF in this note is caused only by acute anaphylaxis."}, {"id": "b", "text": "Long-term HTN is listed HF cause."}, {"id": "c", "text": "Post-MI scar tissue can cause HF."}, {"id": "d", "text": "COPD is linked to right-sided HF in this note."}, {"id": "e", "text": "Valve disease is unrelated to HF in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Heart failure causes listed include post-MI scar, long-term hypertension, valve disease, cardiomyopathy, and COPD causing right-sided failure.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 62, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Left-sided HF signs. Which elements should be included? (Select all that apply)', 'The nurse plans care around Left-sided HF signs. Which elements should be included? (Select all that apply)', '[{"id": "a", "text": "Left HF has no respiratory symptoms in this note."}, {"id": "b", "text": "Pulmonary edema is linked to left HF."}, {"id": "c", "text": "Crackles are left HF sign in this note."}, {"id": "d", "text": "Orthopnea/PND are left HF signs."}, {"id": "e", "text": "Ascites is primary left HF sign in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Left HF signs include pulmonary edema, crackles, dyspnea, orthopnea, and PND.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 63, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Right-sided HF signs? (Select all that apply)', 'During reassessment, which observations support Right-sided HF signs? (Select all that apply)', '[{"id": "a", "text": "JVD is a right HF sign in this note."}, {"id": "b", "text": "Pulmonary crackles are the defining right HF sign in this note."}, {"id": "c", "text": "Ascites is listed in right HF."}, {"id": "d", "text": "Right HF has no edema in this note."}, {"id": "e", "text": "Peripheral edema and weight gain are right HF signs."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Right HF signs include JVD, peripheral edema, ascites, and weight gain.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 64, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues from this scenario are consistent with HF treatment core? (Select all that apply)', 'Which clues from this scenario are consistent with HF treatment core? (Select all that apply)', '[{"id": "a", "text": "Unlimited sodium intake is recommended in this note."}, {"id": "b", "text": "Furosemide is listed to remove fluid."}, {"id": "c", "text": "Low-sodium diet and fluid restriction are listed."}, {"id": "d", "text": "HF treatment in this note excludes all diuretics."}, {"id": "e", "text": "ACEi/ARB and beta-blockers are listed."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: HF treatment listed includes diuretics, ACE inhibitors/ARBs, beta-blockers, digoxin, low sodium diet, and fluid restriction.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 65, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for Cardiac arrest rhythms. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for Cardiac arrest rhythms. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Asystole is shockable in this note."}, {"id": "b", "text": "V-fib and pulseless V-tach are shockable."}, {"id": "c", "text": "PEA should be defibrillated first in this note."}, {"id": "d", "text": "Asystole and PEA are non-shockable."}, {"id": "e", "text": "Rhythm identification guides intervention."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Shockable arrest rhythms are ventricular fibrillation and pulseless ventricular tachycardia; non-shockable are asystole and PEA.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 66, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected Cardiac arrest triggers, which statements are correct? (Select all that apply)', 'For suspected Cardiac arrest triggers, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Drowning and drug overdose are listed triggers."}, {"id": "b", "text": "Only chronic obesity triggers arrest in this note."}, {"id": "c", "text": "Drug overdose cannot cause arrest in this note."}, {"id": "d", "text": "MI is a listed trigger for arrest."}, {"id": "e", "text": "Electrolyte imbalance is listed trigger."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Cardiac arrest can be triggered by MI, electrolyte imbalance, drowning, and drug overdose.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 67, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Cardiac arrest signs. Which elements should be included? (Select all that apply)', 'The nurse plans care around Cardiac arrest signs. Which elements should be included? (Select all that apply)', '[{"id": "a", "text": "Cyanosis can be seen in arrest."}, {"id": "b", "text": "Sudden unconsciousness is expected."}, {"id": "c", "text": "Cardiac arrest patients remain fully alert in this note."}, {"id": "d", "text": "No pulse and no breathing are key signs."}, {"id": "e", "text": "Strong peripheral pulse is typical of arrest in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Key signs are sudden unresponsiveness, no pulse, no breathing, and cyanosis.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 68, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support CAB order? (Select all that apply)', 'During reassessment, which observations support CAB order? (Select all that apply)', '[{"id": "a", "text": "Airway follows compressions in sequence."}, {"id": "b", "text": "Breathing should always start before compressions in this note."}, {"id": "c", "text": "Breathing follows airway in sequence."}, {"id": "d", "text": "Compressions come first in CAB."}, {"id": "e", "text": "CAB means check rhythm before compressions in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Resuscitation sequence emphasizes CAB: Compressions first, then Airway, then Breathing.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 69, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues from this scenario are consistent with Compression quality? (Select all that apply)', 'Which clues from this scenario are consistent with Compression quality? (Select all that apply)', '[{"id": "a", "text": "Shallow compressions are preferred in this note."}, {"id": "b", "text": "Hard, fast compressions are emphasized."}, {"id": "c", "text": "Target rate is 100–120/min."}, {"id": "d", "text": "Depth target is around 2 inches."}, {"id": "e", "text": "Compression rate should be 40/min in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Compressions should be hard and fast, depth about 2 inches, at 100–120 per minute.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 70, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for Defibrillation use. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for Defibrillation use. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "AED is used for V-fib in this note."}, {"id": "b", "text": "All rhythms are treated identically with no shocks in this note."}, {"id": "c", "text": "AED is used for V-tach in this note."}, {"id": "d", "text": "Defibrillation depends on rhythm type."}, {"id": "e", "text": "AED is first-line for asystole in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: AED/defibrillation is indicated for V-fib or V-tach rhythms.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 71, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected Epinephrine timing, which statements are correct? (Select all that apply)', 'For suspected Epinephrine timing, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Epinephrine is given once only then stopped in this note."}, {"id": "b", "text": "Drug timing complements CPR, not replaces it."}, {"id": "c", "text": "Epinephrine is part of arrest protocol in this note."}, {"id": "d", "text": "Epinephrine is contraindicated in all arrest cases in this note."}, {"id": "e", "text": "Epinephrine interval is every 3–5 minutes."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Epinephrine is given every 3–5 minutes during cardiac arrest management.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 72, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around No pulse NCLEX rule. Which elements should be included? (Select all that apply)', 'The nurse plans care around No pulse NCLEX rule. Which elements should be included? (Select all that apply)', '[{"id": "a", "text": "Rhythm check should not delay first compressions."}, {"id": "b", "text": "This is highlighted as a key NCLEX rule."}, {"id": "c", "text": "No pulse should be observed without intervention in this note."}, {"id": "d", "text": "No pulse triggers CPR immediately."}, {"id": "e", "text": "Always check rhythm for several minutes before compressions in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: NCLEX rule in note: if no pulse, start CPR first and do not delay compressions to check rhythm.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 73, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support MI vs arrest distinction? (Select all that apply)', 'During reassessment, which observations support MI vs arrest distinction? (Select all that apply)', '[{"id": "a", "text": "Arrest presents with unresponsiveness and absent pulse."}, {"id": "b", "text": "Arrest patients are typically ambulatory in this note."}, {"id": "c", "text": "Both are emergencies but require different immediate responses."}, {"id": "d", "text": "MI and arrest share identical first actions in this note."}, {"id": "e", "text": "MI can present with chest pain in conscious patient."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: MI patient is usually awake and in pain, while cardiac arrest patient is unresponsive and pulseless.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 74, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues from this scenario are consistent with Key tests by syndrome? (Select all that apply)', 'Which clues from this scenario are consistent with Key tests by syndrome? (Select all that apply)', '[{"id": "a", "text": "Arrest diagnosis depends on BNP trend first in this note."}, {"id": "b", "text": "BNP/echo/chest X-ray are listed for HF."}, {"id": "c", "text": "Rhythm analysis identifies shockable arrest rhythms."}, {"id": "d", "text": "Troponin and ECG are key for MI."}, {"id": "e", "text": "HF diagnosis relies only on troponin in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Key tests listed: MI uses 12-lead ECG and troponin; HF uses BNP/echo/chest X-ray; arrest uses rhythm analysis for shockability.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 75, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for MI definition. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for MI definition. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Myocardial tissue death occurs with sustained ischemia."}, {"id": "b", "text": "MI is an acute emergency condition."}, {"id": "c", "text": "MI involves coronary blood-flow blockage."}, {"id": "d", "text": "MI occurs with absent pulse by definition in this note."}, {"id": "e", "text": "MI is primarily chronic fluid overload in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Heart attack (MI) is blocked coronary blood flow causing heart muscle death.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 76, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected HF definition, which statements are correct? (Select all that apply)', 'For suspected HF definition, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "HF patients may still have a pulse and consciousness."}, {"id": "b", "text": "HF often develops more gradually than MI."}, {"id": "c", "text": "HF is impaired pumping/filling efficiency."}, {"id": "d", "text": "HF means sudden cessation of all heart activity in this note."}, {"id": "e", "text": "HF always presents with no pulse in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: Heart failure is a condition where the heart is too weak or stiff to pump effectively.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 77, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Cardiac arrest definition. Which elements should be included? (Select all that apply)', 'The nurse plans care around Cardiac arrest definition. Which elements should be included? (Select all that apply)', '[{"id": "a", "text": "Cardiac arrest is gradual over months in this note."}, {"id": "b", "text": "Cardiac arrest has absent pulse."}, {"id": "c", "text": "Cardiac arrest patients are unconscious in this note."}, {"id": "d", "text": "Immediate resuscitation is required in arrest."}, {"id": "e", "text": "Cardiac arrest patients are usually awake and conversational in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Cardiac arrest is sudden stop of all effective heart activity, causing no pulse and unresponsiveness.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 78, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Onset differences? (Select all that apply)', 'During reassessment, which observations support Onset differences? (Select all that apply)', '[{"id": "a", "text": "HF is typically gradual in this note."}, {"id": "b", "text": "Cardiac arrest occurs in seconds in this note."}, {"id": "c", "text": "Cardiac arrest develops gradually over weeks in this note."}, {"id": "d", "text": "MI is sudden in this note."}, {"id": "e", "text": "HF generally begins in seconds in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: MI onset is sudden in minutes, heart failure is gradual over weeks-months, and cardiac arrest is immediate in seconds.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 79, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues from this scenario are consistent with Pulse consciousness pattern? (Select all that apply)', 'Which clues from this scenario are consistent with Pulse consciousness pattern? (Select all that apply)', '[{"id": "a", "text": "MI always has no pulse at presentation in this note."}, {"id": "b", "text": "HF patients may have weak but present pulse in this note."}, {"id": "c", "text": "Cardiac arrest has no pulse in this note."}, {"id": "d", "text": "Pulse is absent in uncomplicated HF in this note."}, {"id": "e", "text": "MI often presents while conscious in this note."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: MI and HF generally have a pulse; cardiac arrest has no pulse and unconsciousness.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 80, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for MI causes. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for MI causes. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "Sedentary lifestyle is listed as risk."}, {"id": "b", "text": "HTN/smoking/cholesterol/diabetes are listed risks."}, {"id": "c", "text": "Atherosclerosis and thrombosis are listed MI causes."}, {"id": "d", "text": "Smoking lowers MI risk in this note."}, {"id": "e", "text": "MI in this note is caused only by chronic valve calcification."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: MI causes listed include atherosclerotic plaque and clot blocking coronary artery; risk factors include HTN, smoking, cholesterol, diabetes, sedentary lifestyle.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 81, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected MI symptoms classic, which statements are correct? (Select all that apply)', 'For suspected MI symptoms classic, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "MI pain is always painless in this note."}, {"id": "b", "text": "Radiation to arm/jaw/neck/back is listed."}, {"id": "c", "text": "Diaphoresis and nausea are listed features."}, {"id": "d", "text": "Radiation is absent in MI in this note."}, {"id": "e", "text": "Crushing chest pain is described in MI."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Classic MI symptoms include crushing chest pain, radiation to left arm/jaw/neck/back, diaphoresis, nausea, SOB, and anxiety.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 82, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around MI atypical in women. Which elements should be included? (Select all that apply)', 'The nurse plans care around MI atypical in women. Which elements should be included? (Select all that apply)', '[{"id": "a", "text": "Fatigue can be atypical MI symptom in women."}, {"id": "b", "text": "Women always present with classic elephant-on-chest pain in this note."}, {"id": "c", "text": "Epigastric pain may be atypical MI symptom in women."}, {"id": "d", "text": "Atypical symptoms rule out MI in this note."}, {"id": "e", "text": "Atypical symptoms still warrant urgent evaluation."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Women may present atypically with fatigue and epigastric pain.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 83, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support STEMI vs NSTEMI? (Select all that apply)', 'During reassessment, which observations support STEMI vs NSTEMI? (Select all that apply)', '[{"id": "a", "text": "NSTEMI is partial occlusion in this note."}, {"id": "b", "text": "Troponin elevates in both STEMI and NSTEMI in this note."}, {"id": "c", "text": "STEMI and NSTEMI both have normal troponin in this note."}, {"id": "d", "text": "NSTEMI requires ST elevation in this note."}, {"id": "e", "text": "STEMI is complete occlusion in this note."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: STEMI has ST elevation with complete occlusion; NSTEMI has ST depression with partial occlusion; both have elevated troponin.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 84, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues from this scenario are consistent with MI treatment timing? (Select all that apply)', 'Which clues from this scenario are consistent with MI treatment timing? (Select all that apply)', '[{"id": "a", "text": "Door-to-balloon target is 90 minutes for STEMI."}, {"id": "b", "text": "Thrombolytics are considered if PCI unavailable within 30 minutes."}, {"id": "c", "text": "Thrombolytics are never used when PCI unavailable in this note."}, {"id": "d", "text": "STEMI reperfusion can wait 24 hours in this note."}, {"id": "e", "text": "NSTEMI uses anticoagulants and cardiac cath strategy in this note."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: STEMI requires PCI within 90 minutes; if PCI unavailable, thrombolytics are considered within 30 minutes.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 85, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for MONA in MI. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for MONA in MI. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "MONA excludes aspirin in this note."}, {"id": "b", "text": "Morphine is in MONA in this note."}, {"id": "c", "text": "MONA is a heart-failure-only acronym in this note."}, {"id": "d", "text": "Aspirin is in MONA in this note."}, {"id": "e", "text": "Nitrates are in MONA in this note."}]'::jsonb, '["b", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: MONA includes Morphine, Oxygen, Nitrates, and Aspirin in acute MI management from this note.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 86, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected HF causes, which statements are correct? (Select all that apply)', 'For suspected HF causes, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Post-MI scar tissue can cause HF."}, {"id": "b", "text": "Valve disease is unrelated to HF in this note."}, {"id": "c", "text": "Long-term HTN is listed HF cause."}, {"id": "d", "text": "HF in this note is caused only by acute anaphylaxis."}, {"id": "e", "text": "COPD is linked to right-sided HF in this note."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Heart failure causes listed include post-MI scar, long-term hypertension, valve disease, cardiomyopathy, and COPD causing right-sided failure.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 87, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Left-sided HF signs. Which elements should be included? (Select all that apply)', 'The nurse plans care around Left-sided HF signs. Which elements should be included? (Select all that apply)', '[{"id": "a", "text": "Pulmonary edema is linked to left HF."}, {"id": "b", "text": "Orthopnea/PND are left HF signs."}, {"id": "c", "text": "Left HF has no respiratory symptoms in this note."}, {"id": "d", "text": "Ascites is primary left HF sign in this note."}, {"id": "e", "text": "Crackles are left HF sign in this note."}]'::jsonb, '["a", "b", "e"]'::jsonb, 'Correct selections align with note-based facts: Left HF signs include pulmonary edema, crackles, dyspnea, orthopnea, and PND.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 88, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support Right-sided HF signs? (Select all that apply)', 'During reassessment, which observations support Right-sided HF signs? (Select all that apply)', '[{"id": "a", "text": "Peripheral edema and weight gain are right HF signs."}, {"id": "b", "text": "Right HF has no edema in this note."}, {"id": "c", "text": "JVD is a right HF sign in this note."}, {"id": "d", "text": "Ascites is listed in right HF."}, {"id": "e", "text": "Pulmonary crackles are the defining right HF sign in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Right HF signs include JVD, peripheral edema, ascites, and weight gain.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 89, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues from this scenario are consistent with HF treatment core? (Select all that apply)', 'Which clues from this scenario are consistent with HF treatment core? (Select all that apply)', '[{"id": "a", "text": "HF treatment in this note excludes all diuretics."}, {"id": "b", "text": "ACEi/ARB and beta-blockers are listed."}, {"id": "c", "text": "Furosemide is listed to remove fluid."}, {"id": "d", "text": "Low-sodium diet and fluid restriction are listed."}, {"id": "e", "text": "Unlimited sodium intake is recommended in this note."}]'::jsonb, '["b", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: HF treatment listed includes diuretics, ACE inhibitors/ARBs, beta-blockers, digoxin, low sodium diet, and fluid restriction.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 90, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for Cardiac arrest rhythms. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for Cardiac arrest rhythms. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "PEA should be defibrillated first in this note."}, {"id": "b", "text": "Rhythm identification guides intervention."}, {"id": "c", "text": "V-fib and pulseless V-tach are shockable."}, {"id": "d", "text": "Asystole is shockable in this note."}, {"id": "e", "text": "Asystole and PEA are non-shockable."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Shockable arrest rhythms are ventricular fibrillation and pulseless ventricular tachycardia; non-shockable are asystole and PEA.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 91, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected Cardiac arrest triggers, which statements are correct? (Select all that apply)', 'For suspected Cardiac arrest triggers, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Electrolyte imbalance is listed trigger."}, {"id": "b", "text": "Drowning and drug overdose are listed triggers."}, {"id": "c", "text": "Only chronic obesity triggers arrest in this note."}, {"id": "d", "text": "MI is a listed trigger for arrest."}, {"id": "e", "text": "Drug overdose cannot cause arrest in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Cardiac arrest can be triggered by MI, electrolyte imbalance, drowning, and drug overdose.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 92, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around Cardiac arrest signs. Which elements should be included? (Select all that apply)', 'The nurse plans care around Cardiac arrest signs. Which elements should be included? (Select all that apply)', '[{"id": "a", "text": "Cyanosis can be seen in arrest."}, {"id": "b", "text": "Sudden unconsciousness is expected."}, {"id": "c", "text": "Cardiac arrest patients remain fully alert in this note."}, {"id": "d", "text": "No pulse and no breathing are key signs."}, {"id": "e", "text": "Strong peripheral pulse is typical of arrest in this note."}]'::jsonb, '["a", "b", "d"]'::jsonb, 'Correct selections align with note-based facts: Key signs are sudden unresponsiveness, no pulse, no breathing, and cyanosis.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 93, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support CAB order? (Select all that apply)', 'During reassessment, which observations support CAB order? (Select all that apply)', '[{"id": "a", "text": "Compressions come first in CAB."}, {"id": "b", "text": "CAB means check rhythm before compressions in this note."}, {"id": "c", "text": "Airway follows compressions in sequence."}, {"id": "d", "text": "Breathing should always start before compressions in this note."}, {"id": "e", "text": "Breathing follows airway in sequence."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Resuscitation sequence emphasizes CAB: Compressions first, then Airway, then Breathing.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 94, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues from this scenario are consistent with Compression quality? (Select all that apply)', 'Which clues from this scenario are consistent with Compression quality? (Select all that apply)', '[{"id": "a", "text": "Hard, fast compressions are emphasized."}, {"id": "b", "text": "Compression rate should be 40/min in this note."}, {"id": "c", "text": "Depth target is around 2 inches."}, {"id": "d", "text": "Target rate is 100–120/min."}, {"id": "e", "text": "Shallow compressions are preferred in this note."}]'::jsonb, '["a", "c", "d"]'::jsonb, 'Correct selections align with note-based facts: Compressions should be hard and fast, depth about 2 inches, at 100–120 per minute.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 95, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'A patient is assessed for Defibrillation use. Which findings/actions are appropriate? (Select all that apply)', 'A patient is assessed for Defibrillation use. Which findings/actions are appropriate? (Select all that apply)', '[{"id": "a", "text": "AED is first-line for asystole in this note."}, {"id": "b", "text": "All rhythms are treated identically with no shocks in this note."}, {"id": "c", "text": "AED is used for V-tach in this note."}, {"id": "d", "text": "Defibrillation depends on rhythm type."}, {"id": "e", "text": "AED is used for V-fib in this note."}]'::jsonb, '["c", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: AED/defibrillation is indicated for V-fib or V-tach rhythms.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 96, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'For suspected Epinephrine timing, which statements are correct? (Select all that apply)', 'For suspected Epinephrine timing, which statements are correct? (Select all that apply)', '[{"id": "a", "text": "Drug timing complements CPR, not replaces it."}, {"id": "b", "text": "Epinephrine is given once only then stopped in this note."}, {"id": "c", "text": "Epinephrine is contraindicated in all arrest cases in this note."}, {"id": "d", "text": "Epinephrine is part of arrest protocol in this note."}, {"id": "e", "text": "Epinephrine interval is every 3–5 minutes."}]'::jsonb, '["a", "d", "e"]'::jsonb, 'Correct selections align with note-based facts: Epinephrine is given every 3–5 minutes during cardiac arrest management.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 97, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'The nurse plans care around No pulse NCLEX rule. Which elements should be included? (Select all that apply)', 'The nurse plans care around No pulse NCLEX rule. Which elements should be included? (Select all that apply)', '[{"id": "a", "text": "Rhythm check should not delay first compressions."}, {"id": "b", "text": "No pulse triggers CPR immediately."}, {"id": "c", "text": "This is highlighted as a key NCLEX rule."}, {"id": "d", "text": "Always check rhythm for several minutes before compressions in this note."}, {"id": "e", "text": "No pulse should be observed without intervention in this note."}]'::jsonb, '["a", "b", "c"]'::jsonb, 'Correct selections align with note-based facts: NCLEX rule in note: if no pulse, start CPR first and do not delay compressions to check rhythm.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 98, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'During reassessment, which observations support MI vs arrest distinction? (Select all that apply)', 'During reassessment, which observations support MI vs arrest distinction? (Select all that apply)', '[{"id": "a", "text": "Both are emergencies but require different immediate responses."}, {"id": "b", "text": "MI and arrest share identical first actions in this note."}, {"id": "c", "text": "MI can present with chest pain in conscious patient."}, {"id": "d", "text": "Arrest patients are typically ambulatory in this note."}, {"id": "e", "text": "Arrest presents with unresponsiveness and absent pulse."}]'::jsonb, '["a", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: MI patient is usually awake and in pain, while cardiac arrest patient is unresponsive and pulseless.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 99, 1, true);
  INSERT INTO test_questions (test_id, topic_id, question, question_stem, options, correct_answer, rationale, category, is_multiple_choice, display_order, points, is_active)
  VALUES (v_test_id, v_topic_id, 'Which clues from this scenario are consistent with Key tests by syndrome? (Select all that apply)', 'Which clues from this scenario are consistent with Key tests by syndrome? (Select all that apply)', '[{"id": "a", "text": "Arrest diagnosis depends on BNP trend first in this note."}, {"id": "b", "text": "Rhythm analysis identifies shockable arrest rhythms."}, {"id": "c", "text": "BNP/echo/chest X-ray are listed for HF."}, {"id": "d", "text": "HF diagnosis relies only on troponin in this note."}, {"id": "e", "text": "Troponin and ECG are key for MI."}]'::jsonb, '["b", "c", "e"]'::jsonb, 'Correct selections align with note-based facts: Key tests listed: MI uses 12-lead ECG and troponin; HF uses BNP/echo/chest X-ray; arrest uses rhythm analysis for shockability.', 'MI vs HF vs Cardiac Arrest - NCLEX', true, 100, 1, true);
